from pathlib import Path
import base64
import inspect

TARGET = Path("app/runtime/paper_trading_day_service.py")
CONTENT = base64.b64decode(
    ""
).decode("utf-8")

compile(CONTENT, str(TARGET), "exec")
TARGET.parent.mkdir(parents=True, exist_ok=True)
TARGET.write_text(CONTENT, encoding="utf-8", newline="\n")

from app.runtime.paper_trading_day_service import PaperTradingDayService

signature = inspect.signature(PaperTradingDayService.__init__)
if "dashboard_publisher" not in signature.parameters:
    raise RuntimeError(
        "dashboard_publisherが反映されていません。"
    )

print(f"updated: {TARGET}")
print(signature)
